      if (!row) {
        return;
      }
      if (this.locked) {
        this.hideContextMenu();
        return;
      }
      const id = Number(row.dataset.courseId);
      if (!id) {
        return;
      }
      this.openCourseContextMenu(id, event.clientX, event.clientY);
